struct GoogleMapView: UIViewRepresentable {
    @Binding var selectedCoordinate: CLLocationCoordinate2D

    func makeCoordinator() -> Coordinator {
        Coordinator(selectedCoordinate: $selectedCoordinate)
    }

    func makeUIView(context: Context) -> GMSMapView {
        let camera = GMSCameraPosition.camera(withLatitude: selectedCoordinate.latitude,
                                               longitude: selectedCoordinate.longitude,
                                               zoom: 12)
        let mapView = GMSMapView.map(withFrame: .zero, camera: camera)
        mapView.delegate = context.coordinator
        mapView.settings.myLocationButton = true
        mapView.isMyLocationEnabled = true

        let marker = GMSMarker(position: selectedCoordinate)
        marker.title = "Demo Location"
        marker.snippet = "Tap to explore"
        marker.map = mapView

        context.coordinator.marker = marker
        context.coordinator.mapView = mapView
        return mapView
    }

    func updateUIView(_ uiView: GMSMapView, context: Context) {
        uiView.animate(toLocation: selectedCoordinate)
        context.coordinator.marker?.position = selectedCoordinate
    }

    final class Coordinator: NSObject, GMSMapViewDelegate {
        @Binding var selectedCoordinate: CLLocationCoordinate2D
        weak var mapView: GMSMapView?
        var marker: GMSMarker?

        init(selectedCoordinate: Binding<CLLocationCoordinate2D>) {
            _selectedCoordinate = selectedCoordinate
        }

        func mapView(_ mapView: GMSMapView, didTapAt coordinate: CLLocationCoordinate2D) {
            selectedCoordinate = coordinate
            marker?.position = coordinate
            marker?.snippet = String(format: "%.4f, %.4f", coordinate.latitude, coordinate.longitude)
            marker?.map = mapView
        }
    }
}

final class LocationManager: NSObject, ObservableObject, CLLocationManagerDelegate {
    private let manager = CLLocationManager()

    override init() {
        super.init()
        manager.delegate = self
    }

    func requestAuthorization() {
        manager.requestWhenInUseAuthorization()
    }
}

